import { Persona } from '../core/persona'
import { MemoryManager } from '../memory/manager'
import { ToolRegistry } from '../tools/registry'
import { getProvider, ProviderAdapter } from '../providers/index'
import { AgentConfig, AgentEvent, Message, ToolDefinition } from '../../shared/agent-types'
import { MCPManager } from '../mcp/manager'
import type { MCPServerConfig } from '../mcp/types'
import { matchPlatform, getConnectablePlatforms } from '../hermes/connector'

export type { Persona }

export class Agent {
  private provider: ProviderAdapter
  private tools: ToolRegistry
  private memory: MemoryManager
  private config: AgentConfig
  private history: Message[] = []
  private persona: Persona | null = null
  private mcpManager: MCPManager
  private aborted = false
  private mcpInitialized = false

  constructor(config: AgentConfig) {
    this.config = config
    this.provider = config.provider
    this.tools = new ToolRegistry()
    this.memory = new MemoryManager()
    this.mcpManager = new MCPManager()

    this.registerBuiltinTools()
  }

  // ── MCP ──

  async initMCP(configs?: MCPServerConfig[]): Promise<void> {
    if (this.mcpInitialized) return

    const serverConfigs = configs ?? []
    if (serverConfigs.length === 0) {
      this.mcpInitialized = true
      return
    }

    this.mcpManager.loadConfigs(serverConfigs)
    await this.mcpManager.connectAll()

    this.tools.setMCPManager(this.mcpManager)
    this.tools.registerMCPTools()

    this.mcpInitialized = true
    console.log(`[Agent] MCP: ${this.mcpManager.getToolNames().length} external tools loaded`)
  }

  getMCPManager(): MCPManager {
    return this.mcpManager
  }

  // ── 内置工具 ──

  private registerBuiltinTools() {
    this.tools.register(
      {
        type: 'function',
        function: {
          name: 'search',
          description: '搜索互联网获取最新信息',
          parameters: {
            type: 'object',
            properties: {
              query: { type: 'string', description: '搜索关键词' }
            },
            required: ['query']
          }
        }
      },
      async (_name, args) => {
        return { result: `搜索「${args.query}」— 搜索引擎待接入` }
      }
    )

    this.tools.register(
      {
        type: 'function',
        function: {
          name: 'get_current_time',
          description: '获取当前时间',
          parameters: {
            type: 'object',
            properties: {},
            required: []
          }
        }
      },
      async () => {
        return { time: new Date().toISOString(), timezone: Intl.DateTimeFormat().resolvedOptions().timeZone }
      }
    )

    this.tools.register(
      {
        type: 'function',
        function: {
          name: 'calculator',
          description: '数学计算',
          parameters: {
            type: 'object',
            properties: {
              expression: { type: 'string', description: '数学表达式，如 2+3*4' }
            },
            required: ['expression']
          }
        }
      },
      async (_name, args) => {
        try {
          const result = Function('"use strict"; return (' + args.expression + ')')()
          return { expression: args.expression, result }
        } catch (e: any) {
          return { error: `计算失败: ${e.message}` }
        }
      }
    )

    // platform_connect — returns raw data, LLM generates persona-toned guidance
    this.tools.register(
      {
        type: 'function',
        function: {
          name: 'platform_connect',
          description: '引导用户连接社交平台（微信、QQ、Telegram、飞书、Discord、钉钉）。当用户说「加微信」「加QQ」「连接xx平台」时调用。返回连接步骤数据，你需要用自己的语气引导用户完成每一步。',
          parameters: {
            type: 'object',
            properties: {
              platform: {
                type: 'string',
                description: '平台名称：qq、weixin、telegram、feishu、discord、dingtalk。也可传用户原话。',
              },
              action: {
                type: 'string',
                enum: ['get_steps', 'list_platforms'],
                description: 'get_steps=获取连接步骤, list_platforms=列出可连接平台',
              },
            },
            required: ['action'],
          },
        },
      },
      async (_name, args) => {
        const { action, platform } = args

        if (action === 'list_platforms') {
          const flows = getConnectablePlatforms()
          return {
            platforms: flows.map(f => ({
              name: f.platform,
              displayName: f.displayName,
              icon: f.icon,
            })),
          }
        }

        const flow = matchPlatform(platform ?? '')
        if (!flow) {
          return {
            supported: ['qq', 'weixin', 'telegram', 'feishu', 'discord', 'dingtalk'],
          }
        }

        return {
          platform: flow.displayName,
          icon: flow.icon,
          steps: flow.steps,
        }
      }
    )
  }

  // ── 消息发送 ──

  async *sendMessage(content: string): AsyncGenerator<AgentEvent> {
    if (!this.mcpInitialized) {
      await this.initMCP()
    }

    const context = await this.buildContext()

    const userMsg: Message = {
      role: 'user',
      content,
      timestamp: Date.now()
    }
    this.history.push(userMsg)
    yield { type: 'message', content: userMsg }

    const toolDefs = this.tools.getDefinitions()

    let fullContent = ''
    let response: Message | null = null

    try {
      for await (const token of this.provider.chatStream(context, this.config.model, toolDefs)) {
        fullContent += token
        yield { type: 'token', content: token }
      }

      if (toolDefs.length > 0) {
        response = await this.provider.chat(context, this.config.model, toolDefs)
      } else {
        response = { role: 'assistant', content: fullContent, timestamp: Date.now() }
      }
    } catch (error: any) {
      yield { type: 'error', error: error.message }
      return
    }

    if (response.tool_calls && response.tool_calls.length > 0) {
      yield { type: 'tool_start', toolCalls: response.tool_calls }

      for (const tc of response.tool_calls) {
        const parsedArgs = JSON.parse(tc.function.arguments)
        yield { type: 'tool_call', name: tc.function.name, args: parsedArgs }

        const result = await this.tools.execute(tc.function.name, parsedArgs)

        yield { type: 'tool_result', name: tc.function.name, content: result }

        const toolMsg: Message = {
          role: 'tool',
          tool_call_id: tc.id,
          content: typeof result === 'string' ? result : JSON.stringify(result),
          timestamp: Date.now()
        }
        this.history.push(toolMsg)
        context.push(toolMsg)
      }

      yield* this.sendMessage('')
    }

    if (response) {
      this.history.push(response)
      yield { type: 'message', content: response }
    }

    if (this.history.length % 10 !== 0) return

    try {
      await this.memory.extractAndSave(this.history)
    } catch (error) {
      console.error('记忆提取失败:', error)
    }
  }

  private async buildContext(): Promise<Message[]> {
    const context: Message[] = []

    const systemPrompt = this.buildSystemPrompt()
    context.push({ role: 'system', content: systemPrompt, timestamp: Date.now() })

    const lastMsg = this.history.length > 0 ? this.history[this.history.length - 1].content || "" : ""
    const memoryContext = await this.memory.search(lastMsg, 5)
    if (memoryContext) {
      context.push({ role: 'system', content: `相关记忆：\n${memoryContext}`, timestamp: Date.now() })
    }

    context.push(...this.history)

    return context
  }

  private buildSystemPrompt(): string {
    let prompt = ''

    if (this.persona) {
      prompt += `## 你是谁\n${this.persona.systemPrompt}\n\n`
      if (this.persona.name) {
        prompt += `你的名字是${this.persona.name}。\n\n`
      }
    }

    const toolDefs = this.tools.getDefinitions()
    if (toolDefs.length > 0) {
      prompt += '## 可用工具\n'
      toolDefs.forEach(def => {
        prompt += `- ${def.function.name}: ${def.function.description}\n`
      })
    }

    return prompt
  }

  setPersona(persona: Persona) {
    this.persona = persona
  }

  getHistory(): Message[] {
    return [...this.history]
  }

  clearHistory() {
    this.history = []
  }

  async getMemoryStats() {
    return { count: this.memory.count(), type: "memory" }
  }


  // 更新配置（桥接器调用）
  updateConfig(patch: Partial<AgentConfig>): void {
    Object.assign(this.config, patch)
  }

  // 中止当前请求
  abort(): void {
    this.aborted = true
  }

  destroy(): void {
    this.mcpManager.disconnectAll()
    this.mcpInitialized = false
  }
}

