import type { ToolDefinition } from '../../shared/agent-types'
import { matchPlatform, getConnectablePlatforms } from './connector'
import type { HermesBridge } from './bridge'

export function createPlatformConnectTool(bridge?: HermesBridge) {
  return {
    definition: {
      type: 'function' as const,
      function: {
        name: 'platform_connect',
        description: '引导用户连接社交平台（微信、QQ、Telegram、飞书、Discord、钉钉）。当用户说「加微信」「加QQ」「连接xx」时调用。返回步骤数据，用你的语气引导用户。',
        parameters: {
          type: 'object',
          properties: {
            platform: {
              type: 'string',
              description: '平台名：qq/weixin/telegram/feishu/discord/dingtalk，或用户原话',
            },
            action: {
              type: 'string',
              enum: ['get_steps', 'list_platforms', 'check_status'],
              description: 'get_steps=获取步骤, list_platforms=列出平台, check_status=查状态',
            },
          },
          required: ['action'],
        },
      },
    },

    handler: async (_name: string, args: any) => {
      const { action, platform } = args

      if (action === 'list_platforms') {
        return {
          platforms: getConnectablePlatforms().map(f => ({
            name: f.platform,
            displayName: f.displayName,
            icon: f.icon,
          })),
        }
      }

      if (action === 'check_status') {
        if (!bridge) return { error: 'Hermes not started' }
        try {
          const platforms = await bridge.getPlatforms()
          return {
            connected: platforms.filter(p => p.connected),
            available: platforms.filter(p => !p.connected),
          }
        } catch (e: any) {
          return { error: e.message }
        }
      }

      const flow = matchPlatform(platform ?? '')
      if (!flow) {
        return { supported: ['qq', 'weixin', 'telegram', 'feishu', 'discord', 'dingtalk'] }
      }
      return { platform: flow.displayName, icon: flow.icon, steps: flow.steps }
    },
  }
}

/**
 * Memory Manager — 基于 Hermes memory_manager.py 重写
 * 简单的文件存储记忆系统，带重要性衰减和搜索
 */
import type { MemoryEntry, Message } from '../../shared/agent-types'

export class MemoryManager {
  private memories: MemoryEntry[] = []
  private storageKey = 'chat-gusogst-memory'

  constructor() { this.load() }

  private load() {
    try {
      const raw = localStorage.getItem(this.storageKey)
      if (raw) this.memories = JSON.parse(raw)
    } catch { this.memories = [] }
  }

  private save() {
    localStorage.setItem(this.storageKey, JSON.stringify(this.memories))
  }

  /** 搜索相关记忆 */
  async search(query: string, limit = 5): Promise<MemoryEntry[]> {
    const queryLower = query.toLowerCase()
    const scored = this.memories
      .map(m => {
        let score = 0
        // 关键词匹配
        const words = queryLower.split(/\s+/)
        for (const w of words) {
          if (m.content.toLowerCase().includes(w)) score += 0.3
        }
        // 标签匹配
        for (const tag of m.tags) {
          if (queryLower.includes(tag.toLowerCase())) score += 0.2
        }
        // 重要性加权
        score *= m.importance
        // 时间衰减（24小时半衰期）
        const age = Date.now() - new Date(m.created_at).getTime()
        score *= Math.pow(0.5, age / (24 * 3600 * 1000))
        // 访问频次加权
        score *= 1 + Math.log(1 + m.access_count)
        return { entry: m, score }
      })
      .filter(x => x.score > 0.01)
      .sort((a, b) => b.score - a.score)
      .slice(0, limit)

    // 更新访问计数
    for (const { entry } of scored) {
      entry.access_count++
      entry.last_accessed = new Date().toISOString()
    }
    this.save()

    return scored.map(x => x.entry)
  }

  /** 添加记忆 */
  async add(content: string, type: MemoryEntry['type'], importance = 0.5, tags: string[] = []): Promise<MemoryEntry> {
    const entry: MemoryEntry = {
      id: `mem_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      content, type, importance, tags,
      created_at: new Date().toISOString(),
      last_accessed: new Date().toISOString(),
      access_count: 0,
    }
    this.memories.push(entry)
    this.save()
    return entry
  }

  /** 从对话历史中提取记忆（简化版，实际应调模型提取） */
  async extractAndSave(messages: Message[]): Promise<number> {
    // 简单策略：记录最近的用户偏好和事实
    let saved = 0
    for (const msg of messages) {
      if (msg.role !== 'user' || !msg.content) continue
      // 检测偏好表达
      const prefPatterns = [
        /我喜欢(.+)/, /我讨厌(.+)/, /我不喜欢(.+)/,
        /我想要(.+)/, /我需要(.+)/, /帮我记住(.+)/,
      ]
      for (const pat of prefPatterns) {
        const match = msg.content.match(pat)
        if (match) {
          await this.add(match[0], 'preference', 0.8, ['偏好'])
          saved++
        }
      }
    }
    return saved
  }

  /** 清除所有记忆 */
  count(): number { return this.memories.length }

  clear() {
    this.memories = []
    this.save()
  }

  /** 获取所有记忆 */
  getAll(): MemoryEntry[] { return [...this.memories] }
}

/**
 * Anthropic Claude Provider
 */
import type { Message, ModelConfig, ProviderAdapter, ToolDefinition } from '../../shared/agent-types'

export class AnthropicProvider implements ProviderAdapter {
  readonly name = 'anthropic'

  private getEndpoint(config: ModelConfig): string {
    const host = (config.apiHost || 'https://api.anthropic.com').replace(/\/+$/, '')
    return `${host}/v1/messages`
  }

  private convertMessages(messages: Message[]): { system?: string; messages: unknown[] } {
    let system: string | undefined
    const converted: unknown[] = []
    for (const m of messages) {
      if (m.role === 'system') {
        system = m.content ?? undefined
        continue
      }
      if (m.role === 'tool') {
        converted.push({
          role: 'user',
          content: [{ type: 'tool_result', tool_use_id: m.tool_call_id, content: m.content }],
        })
        continue
      }
      const msg: Record<string, unknown> = { role: m.role }
      if (m.tool_calls && m.tool_calls.length > 0) {
        const parts: unknown[] = []
        if (m.content) parts.push({ type: 'text', text: m.content })
        for (const tc of m.tool_calls) {
          parts.push({
            type: 'tool_use', id: tc.id, name: tc.function.name,
            input: JSON.parse(tc.function.arguments),
          })
        }
        msg.content = parts
      } else {
        msg.content = m.content
      }
      converted.push(msg)
    }
    return { system, messages: converted }
  }

  private convertTools(tools?: ToolDefinition[]): unknown[] | undefined {
    if (!tools?.length) return undefined
    return tools.map(t => ({
      name: t.function.name,
      description: t.function.description,
      input_schema: t.function.parameters,
    }))
  }

  async chat(messages: Message[], config: ModelConfig, tools?: ToolDefinition[]): Promise<Message> {
    const { system, messages: msgs } = this.convertMessages(messages)
    const body: Record<string, unknown> = {
      model: config.model,
      messages: msgs,
      max_tokens: config.maxTokens ?? 8192,
    }
    if (system) body.system = system
    if (config.temperature != null) body.temperature = config.temperature
    const convertedTools = this.convertTools(tools)
    if (convertedTools) body.tools = convertedTools

    const resp = await fetch(this.getEndpoint(config), {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': config.apiKey,
        'anthropic-version': '2023-06-01',
      },
      body: JSON.stringify(body),
    })
    if (!resp.ok) throw new Error(`[anthropic] ${resp.status}: ${await resp.text()}`)
    const data = await resp.json()
    const contentBlocks = data.content || []
    let text = ''
    const toolCalls: Message['tool_calls'] = []
    for (const block of contentBlocks) {
      if (block.type === 'text') text += block.text
      if (block.type === 'tool_use') {
        toolCalls!.push({
          id: block.id, type: 'function',
          function: { name: block.name, arguments: JSON.stringify(block.input) },
        })
      }
    }
    return { role: 'assistant', content: text || null, tool_calls: toolCalls?.length ? toolCalls : undefined, timestamp: Date.now() }
  }

  async *chatStream(messages: Message[], config: ModelConfig, tools?: ToolDefinition[]): AsyncGenerator<string> {
    // Anthropic SSE streaming — simplified, expand as needed
    const result = await this.chat(messages, config, tools)
    if (result.content) yield result.content
  }
}

import type { ProviderAdapter } from '../../shared/agent-types'
import { OpenAIProvider } from './openai'
import { AnthropicProvider } from './anthropic'

const providers: Record<string, ProviderAdapter> = {}

function register(p: ProviderAdapter) { providers[p.name] = p }

register(new OpenAIProvider())
register(new AnthropicProvider())

export function getProvider(name: string): ProviderAdapter {
  const p = providers[name]
  if (!p) throw new Error(`Unknown provider: ${name}. Available: ${Object.keys(providers).join(', ')}`)
  return p
}

export function listProviders(): string[] { return Object.keys(providers) }

export function registerProvider(p: ProviderAdapter) { register(p) }
