/**
 * OpenAI 兼容 Provider
 * 支持: OpenAI, Deepseek, Groq, Together, 硅基流动, 自定义端点
 */
import type { Message, ModelConfig, ProviderAdapter, ToolDefinition } from '../../shared/agent-types'

export class OpenAIProvider implements ProviderAdapter {
  readonly name = 'openai'

  private getEndpoint(config: ModelConfig): string {
    const host = (config.apiHost || 'https://api.openai.com').replace(/\/+$/, '')
    return `${host}/v1/chat/completions`
  }

  private buildBody(messages: Message[], config: ModelConfig, tools?: ToolDefinition[], stream = false) {
    const body: Record<string, unknown> = {
      model: config.model,
      messages: messages.map(m => {
        const msg: Record<string, unknown> = { role: m.role, content: m.content }
        if (m.tool_calls) msg.tool_calls = m.tool_calls
        if (m.tool_call_id) msg.tool_call_id = m.tool_call_id
        if (m.name) msg.name = m.name
        return msg
      }),
      stream,
    }
    if (config.temperature != null) body.temperature = config.temperature
    if (config.maxTokens != null) body.max_tokens = config.maxTokens
    if (config.topP != null) body.top_p = config.topP
    if (tools && tools.length > 0) body.tools = tools
    return body
  }

  private parseSSELine(line: string): string | null {
    if (!line.startsWith('data: ')) return null
    const data = line.slice(6).trim()
    if (data === '[DONE]') return null
    try {
      const parsed = JSON.parse(data)
      return parsed.choices?.[0]?.delta?.content ?? null
    } catch { return null }
  }

  async chat(messages: Message[], config: ModelConfig, tools?: ToolDefinition[]): Promise<Message> {
    const resp = await fetch(this.getEndpoint(config), {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${config.apiKey}`,
      },
      body: JSON.stringify(this.buildBody(messages, config, tools, false)),
    })
    if (!resp.ok) {
      const err = await resp.text()
      throw new Error(`[${this.name}] ${resp.status}: ${err}`)
    }
    const data = await resp.json()
    const choice = data.choices?.[0]
    if (!choice) throw new Error('No choice in response')
    return {
      role: 'assistant',
      content: choice.message?.content ?? null,
      tool_calls: choice.message?.tool_calls,
      timestamp: Date.now(),
    }
  }

  async *chatStream(messages: Message[], config: ModelConfig, tools?: ToolDefinition[]): AsyncGenerator<string> {
    const resp = await fetch(this.getEndpoint(config), {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${config.apiKey}`,
      },
      body: JSON.stringify(this.buildBody(messages, config, tools, true)),
    })
    if (!resp.ok) {
      const err = await resp.text()
      throw new Error(`[${this.name}] ${resp.status}: ${err}`)
    }
    const reader = resp.body?.getReader()
    if (!reader) throw new Error('No response body')
    const decoder = new TextDecoder()
    let buffer = ''
    try {
      while (true) {
        const { done, value } = await reader.read()
        if (done) break
        buffer += decoder.decode(value, { stream: true })
        const lines = buffer.split('\n')
        buffer = lines.pop() ?? ''
        for (const line of lines) {
          const token = this.parseSSELine(line)
          if (token !== null) yield token
        }
      }
    } finally {
      reader.releaseLock()
    }
  }
}

import { ToolDefinition } from '../../shared/agent-types'
import type { MCPManager } from '../mcp/manager'

export class ToolRegistry {
  private tools = new Map<string, ToolDefinition>()
  private handlers = new Map<string, (name: string, args: any) => Promise<any>>()
  private mcpManager: MCPManager | null = null

  setMCPManager(manager: MCPManager): void {
    this.mcpManager = manager
  }

  registerMCPTools(): void {
    if (!this.mcpManager) return

    for (const def of this.mcpManager.getAllToolDefinitions()) {
      this.register({
        type: 'function',
        function: {
          name: def.name,
          description: def.description,
          parameters: def.parameters,
        }
      })
    }
  }

  register(tool: ToolDefinition, handler?: (name: string, args: any) => Promise<any>): void {
    this.tools.set(tool.function.name, tool)
    if (handler) {
      this.handlers.set(tool.function.name, handler)
    }
  }

  registerWithHandler(name: string, handler: (name: string, args: any) => Promise<any>): void {
    this.handlers.set(name, handler)
  }

  get(name: string): ToolDefinition | undefined {
    return this.tools.get(name)
  }

  has(name: string): boolean {
    return this.tools.has(name)
  }

  getDefinitions(): ToolDefinition[] {
    return Array.from(this.tools.values())
  }

  get names(): string[] {
    return Array.from(this.tools.keys())
  }

  async execute(name: string, args: any): Promise<any> {
    // Check if this is an MCP tool
    if (this.mcpManager?.getToolNames().includes(name)) {
      try {
        const result = await this.mcpManager.callTool(name, args)
        if (result.isError) {
          const errorText = result.content
            .filter((c: any) => c.type === 'text')
            .map((c: any) => c.text)
            .join('\n')
          return { error: errorText }
        }
        const textParts = result.content.filter((c: any) => c.type === 'text')
        if (textParts.length === result.content.length) {
          return textParts.map((c: any) => c.text).join('\n')
        }
        return result.content
      } catch (error: any) {
        return { error: `MCP tool '${name}' failed: ${error.message}` }
      }
    }

    // Built-in handler
    const handler = this.handlers.get(name)
    if (!handler) {
      return { error: `Tool '${name}' not found` }
    }

    try {
      return await handler(name, args)
    } catch (error: any) {
      return { error: `Tool '${name}' failed: ${error.message}` }
    }
  }
}

/**
 * 搜索工具 — 支持 Tavily / DuckDuckGo / 百度
 * 基于 Hermes websearch.py 重写
 */
import { ToolRegistry } from './registry'

export function registerSearchTools(registry: ToolRegistry, config: {
  engine: string
  apiKey?: string
}) {
  registry.register(
    {
      type: 'function',
      function: {
        name: 'web_search',
        description: '搜索互联网获取实时信息。当用户询问新闻、实时数据、你不了解的信息时使用。',
        parameters: {
          type: 'object',
          properties: {
            query: { type: 'string', description: '搜索关键词' },
            max_results: { type: 'number', description: '返回结果数量，默认5' },
          },
          required: ['query'],
        },
      },
    },
    async (_name: string, args: Record<string, unknown>) => {
      const query = args.query as string
      const maxResults = (args.max_results as number) || 5

      try {
        if (config.engine === 'tavily' && config.apiKey) {
          return await searchTavily(query, config.apiKey, maxResults)
        }
        return await searchDuckDuckGo(query, maxResults)
      } catch (err: any) {
        return JSON.stringify({ error: err.message })
      }
    },
  )
}

async function searchTavily(query: string, apiKey: string, maxResults: number): Promise<string> {
  const resp = await fetch('https://api.tavily.com/search', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      api_key: apiKey,
      query,
      max_results: maxResults,
      include_answer: true,
    }),
  })
  if (!resp.ok) throw new Error(`Tavily error: ${resp.status}`)
  const data = await resp.json()
  const results = (data.results || []).map((r: any) => ({
    title: r.title,
    url: r.url,
    snippet: r.content?.slice(0, 200),
  }))
  return JSON.stringify({ answer: data.answer, results })
}

async function searchDuckDuckGo(query: string, maxResults: number): Promise<string> {
  // DuckDuckGo Instant Answer API (免费，无需 key)
  const params = new URLSearchParams({ q: query, format: 'json', no_html: '1', skip_disambig: '1' })
  const resp = await fetch(`https://api.duckduckgo.com/?${params}`)
  if (!resp.ok) throw new Error(`DuckDuckGo error: ${resp.status}`)
  const data = await resp.json()
  const results: Array<{ title: string; snippet: string }> = []
  if (data.Abstract) {
    results.push({ title: data.Heading || query, snippet: data.Abstract })
  }
  for (const topic of (data.RelatedTopics || []).slice(0, maxResults)) {
    if (topic.Text) {
      results.push({ title: topic.Text?.slice(0, 80), snippet: topic.Text })
    }
  }
  return JSON.stringify({ results })
}

/**
 * Bridge — 连接 Agent 和 UI
 * 在 Android (Capacitor) 和桌面 (Electron) 中统一使用
 */
import { Agent } from '../agent/core/agent'
import type { AgentConfig, AgentEvent, Persona } from '../shared/agent-types'

class AgentBridge {
  private agent: Agent | null = null
  private config: AgentConfig | null = null

  async init(config: AgentConfig): Promise<void> {
    this.config = config
    this.agent = new Agent(config)
  }

  isReady(): boolean { return this.agent !== null }

  updateConfig(patch: Partial<AgentConfig>) {
    if (!this.agent || !this.config) return
    Object.assign(this.config, patch)
    this.agent.updateConfig(patch)
  }

  async *chat(message: string): AsyncGenerator<AgentEvent> {
    if (!this.agent) throw new Error('Agent not initialized')
    yield* this.agent.sendMessage(message)
  }

  abort() { this.agent?.abort() }
  clearHistory() { this.agent?.clearHistory() }
  getHistory() { return this.agent?.getHistory() ?? [] }

  switchPersona(persona: Persona) {
    if (!this.config) return
    this.config.persona = persona
    this.agent?.updateConfig({ persona })
  }
}

// 单例
export const bridge = new AgentBridge()
export type { AgentBridge }

